import numpy as np

def frobenius_norm(A):
    A = np.asarray(A, dtype=float)
    return float(np.sqrt(np.sum(A ** 2)))


def nuclear_norm_approx(A, k=None):
    A = np.asarray(A, dtype=float)
    S = np.linalg.svd(A, compute_uv=False)
    if k is not None:
        S = S[:k]
    return float(np.sum(S))
